{
  "verses": [
    {
      "n": 11,
      "column": "left",
      "text": "Tad fazzija tas Deewa\nEngelis us man Sapni: Jeh-\nkabs/ un es fazziju : sche es esinnu.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Un tas fazzija : Pazell\njelle tawas Azzis / un skattajs/\nwiffi Tekkuki apjauxahs ar tahm\neeraibahin / lahfainahin un rai-\nbahm Awim / jo es esinn to wif-\nfu redsejis/ ko tew Lahbans darra.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Es esinn tas STIP-\nRAJS Beteles DEEWS/kur\ntu to uszeltu Sihmi fwaidijts\nefi / kur tu man apfohldamees\nefi apfohltijees / zellees nu / un\ntseij no schahs Semnes / un at-\ngresees us tawu Dsunteni.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Tad atbildeja Raële / un\nLea / un fazzija us to : Woj irr\nnumms wehl Dalliba un Eeman-\ntoschana muhsu Tehwa Namunâ?\n"
    },
    {
      "n": 15,
      "column": "left",
      "text": "Neggi mehs par Swe-\nschahm no winna eſſam turretas/\njo wiꞥsch irr muhs pahrdevis/un\narridsan muhsu Naudu aprily-\ndanis aprithjis.\n"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Jo wiffa Baggatiba / ko\nDeews muhsu Tehwain irr at-\nrehmis/ peederr numms un muhs-\nfu Behrneem / un nu / wiffu/ ko\nDEews us tew irr fazzijis / to\ndarri.\n"
    },
    {
      "n": 17,
      "column": "left",
      "text": "Un Jehkabs zehlahs / un\nlkeke fawus Behrnes / un fawas\nSeetas us Kaneeteem.\n"
    },
    {
      "n": 18,
      "column": "left",
      "text": "Un aiswedde wiffus fa-\nwus Lohpus / un wiffu fawu\nMantu/ ko wiꞥsch Mesopotami-\njâ bij pelnijis / ka tas nahktu pee\nIhsääku fawn Tehwu/us Kanâ-\näna Semuni.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Un Lahbans bij ais-\nfawas Awis zirpt / un Ra-\nga tohs Elka-Deewus / ka-\nnas Tehwain bij.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Un tad sagga Jehkab-\nbanam tam Sihrexam to G\nka tas winnam ne fazzija\ntas behgtu.\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Un winſch behdfe/un-\nfas winnam bij / un zehla-\npahrzehlahs pahr Uppi / u-\nsahs teescham us to Kaln\nleäd.\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Un treschâ Deenâ\nLahbanam fazzihts: Jehk-\nfam nobehgnischu.\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Tad nehme tas\nBrahtus / un dsinnahs ta-\nkat septix Deeno Gahjum-\npanahze to wirs to Kalnu G\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Tomehr Deews na-\nLahbanu to Sihleri Sap-\nfazzija us to : fargajs / k-\nJehkabu ne runna no lab-\ntannu.\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Un Lahbans panah-\nkabu/ un Jehkabs bij faw-\nti uszehlis Kalnâ / un La-\nar faweem Brahteem /\n(fawu Telti) us to Kaln\nleäd.\n"
    },
    {
      "n": 26,
      "column": "right",
      "text": "Tad fazzija Lahba-\nJehkabu : ko eſſi tu darrijis-\nmannu Sirdi eſſi pasadsie-\nmannas Meitas aisweddis-\nkâ zaur Sobbinu faxemta\n"
    },
    {
      "n": 27,
      "column": "right",
      "text": "Kam eſſi tu pattepp-\nbehdsis / un tew no man-\nsees / un ne eſſi man to pa-\njs / ka es tew buhtu paw-\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
